function TerminalSplit({ appName, version, status, hotkeys, children }) {
  const { div, header, main, footer, span, kbd } = tags;
  const [paneWidths, setPaneWidths] = createSignal([50, 50]);

  const handleKeyDown = (e) => {
    const hotkey = hotkeys.find(h => h.key === e.key);
    if (hotkey) {
      e.preventDefault();
      hotkey.action();
    }
  };

  onMount(() => document.addEventListener('keydown', handleKeyDown));
  onDestroy(() => document.removeEventListener('keydown', handleKeyDown));

  return div({ class: css('_grid _h[100vh] _mono _bgblack _fggreen'), style: 'grid-template-rows: 24px 1fr 28px' },
    // Status bar
    header({ class: css('_flex _aic _jcsb _px2 _bggreen _fgblack _textsm') },
      span({}, `${appName} v${version}`),
      span({}, `[status: ${status}]`)
    ),
    // Split pane body
    main({ class: css('_flex _overflow[hidden] _p2') },
      div({ class: css('term-panel _flex1 _overflow[auto] _p2'), style: () => `width: ${paneWidths()[0]}%` },
        children[0]
      ),
      div({ class: css('_w1 _cursor[col-resize] _bgborder') }),
      div({ class: css('term-panel _flex1 _overflow[auto] _p2'), style: () => `width: ${paneWidths()[1]}%` },
        children[1]
      )
    ),
    // Hotkey bar
    footer({ class: css('_flex _aic _gap4 _px2 _bgmuted _textsm') },
      ...hotkeys.map(h =>
        div({ class: css('_flex _aic _gap1'), onclick: h.action },
          kbd({ class: css('term-hotkey _px1 _border _r1') }, h.key),
          span({ class: css('_fgmuted') }, h.label)
        )
      )
    )
  );
}
